import io
import logging
import numpy as np
import torch
import torch.nn.functional as F
import torchvision.transforms as transforms
import torchvision.models as models
from PIL import Image
from flask import Flask, request, jsonify

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Load pretrained model
model = models.resnet50(pretrained=True)
model.eval()

# Load ImageNet class labels
try:
    with open("imagenet_classes.txt", "r") as f:
        IMAGENET_CLASSES = [line.strip() for line in f.readlines()]
except FileNotFoundError:
    IMAGENET_CLASSES = [f"class_{i}" for i in range(1000)]

# Standard preprocessing pipeline
PREPROCESS = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# --- Adversarial Defense Utilities ---

MAX_IMAGE_SIZE = 10 * 1024 * 1024  # 10 MB
MAX_DIMENSION = 4096
MIN_DIMENSION = 16
ALLOWED_FORMATS = {"JPEG", "PNG", "BMP", "WEBP"}
CONFIDENCE_THRESHOLD = 0.1  # Minimum confidence to return a prediction
ENTROPY_THRESHOLD = 6.0  # High entropy in output logits may indicate adversarial input
INPUT_SMOOTHING_KERNEL_SIZE = 3  # Gaussian smoothing to reduce adversarial perturbations
JPEG_COMPRESSION_QUALITY = 85  # JPEG compression as adversarial defense


def validate_image(file_storage):
    """Validate uploaded image file for safety and correctness."""
    # Check file size
    file_storage.seek(0, 2)
    file_size = file_storage.tell()
    file_storage.seek(0)

    if file_size == 0:
        raise ValueError("Empty file uploaded")
    if file_size > MAX_IMAGE_SIZE:
        raise ValueError(f"File too large: {file_size} bytes (max {MAX_IMAGE_SIZE})")

    # Read and validate with PIL
    try:
        image = Image.open(file_storage)
        image.verify()
        file_storage.seek(0)
        image = Image.open(file_storage)
    except Exception:
        raise ValueError("Invalid or corrupted image file")

    # Check format
    if image.format and image.format.upper() not in ALLOWED_FORMATS:
        raise ValueError(f"Unsupported image format: {image.format}. Allowed: {ALLOWED_FORMATS}")

    # Check dimensions
    width, height = image.size
    if width > MAX_DIMENSION or height > MAX_DIMENSION:
        raise ValueError(f"Image dimensions too large: {width}x{height} (max {MAX_DIMENSION}x{MAX_DIMENSION})")
    if width < MIN_DIMENSION or height < MIN_DIMENSION:
        raise ValueError(f"Image dimensions too small: {width}x{height} (min {MIN_DIMENSION}x{MIN_DIMENSION})")

    # Convert to RGB (handles RGBA, grayscale, palette, etc.)
    image = image.convert("RGB")

    return image


def apply_jpeg_compression_defense(image, quality=JPEG_COMPRESSION_QUALITY):
    """
    Apply JPEG compression as an adversarial defense.
    JPEG compression removes high-frequency adversarial perturbations.
    """
    buffer = io.BytesIO()
    image.save(buffer, format="JPEG", quality=quality)
    buffer.seek(0)
    return Image.open(buffer).convert("RGB")


def apply_spatial_smoothing(tensor, kernel_size=INPUT_SMOOTHING_KERNEL_SIZE):
    """
    Apply Gaussian-like spatial smoothing to input tensor to mitigate adversarial perturbations.
    Uses average pooling as a simple smoothing mechanism.
    """
    if kernel_size <= 1:
        return tensor
    padding = kernel_size // 2
    # Apply average pooling as smoothing
    smoothed = F.avg_pool2d(tensor, kernel_size=kernel_size, stride=1, padding=padding)
    return smoothed


def check_pixel_range(image):
    """
    Check if pixel values are within expected natural image ranges.
    Adversarial images sometimes have unusual pixel distributions.
    """
    img_array = np.array(image, dtype=np.float32)

    # Check for NaN or Inf values
    if np.any(np.isnan(img_array)) or np.any(np.isinf(img_array)):
        raise ValueError("Image contains invalid pixel values (NaN or Inf)")

    # Check pixel value variance - completely uniform images are suspicious
    if np.std(img_array) < 1.0:
        logger.warning("Image has extremely low variance - potentially synthetic/adversarial")

    return True


def compute_prediction_entropy(probabilities):
    """
    Compute entropy of the prediction distribution.
    High entropy may indicate adversarial inputs that confuse the model.
    """
    probs = probabilities.clamp(min=1e-10)
    entropy = -(probs * probs.log()).sum().item()
    return entropy


def detect_adversarial_signals(input_tensor, logits, probabilities):
    """
    Run multiple heuristic checks to detect potential adversarial examples.
    Returns (is_suspicious, reasons).
    """
    reasons = []

    # Check 1: High entropy in output distribution
    entropy = compute_prediction_entropy(probabilities)
    max_entropy = np.log(probabilities.shape[-1])  # Maximum possible entropy
    normalized_entropy = entropy / max_entropy
    if normalized_entropy > 0.95:
        reasons.append(f"Extremely high output entropy: {normalized_entropy:.4f}")

    # Check 2: Unusually high L2 norm of input tensor (after normalization)
    input_l2 = input_tensor.norm(2).item()
    # For a 224x224x3 normalized image, typical L2 norm range
    expected_max_l2 = 150.0
    if input_l2 > expected_max_l2:
        reasons.append(f"Unusual input L2 norm: {input_l2:.2f}")

    # Check 3: Check for high-frequency content that might indicate perturbations
    # Compute gradient magnitude as proxy for high-frequency content
    if input_tensor.dim() == 4 and input_tensor.shape[2] > 2 and input_tensor.shape[3] > 2:
        dx = (input_tensor[:, :, :, 1:] - input_tensor[:, :, :, :-1]).abs().mean().item()
        dy = (input_tensor[:, :, 1:, :] - input_tensor[:, :, :-1, :]).abs().mean().item()
        gradient_magnitude = dx + dy
        # Unusually high gradient magnitude may indicate adversarial perturbation
        if gradient_magnitude > 2.0:
            reasons.append(f"High gradient magnitude: {gradient_magnitude:.4f}")

    # Check 4: Top prediction confidence is suspiciously extreme
    top_prob = probabilities.max().item()
    if top_prob > 0.9999:
        reasons.append(f"Suspiciously high confidence: {top_prob:.6f}")

    is_suspicious = len(reasons) > 0
    return is_suspicious, reasons


@app.route("/predict", methods=["POST"])
def predict():
    """Accept an image via HTTP POST and return predicted class and confidence."""
    try:
        # Check that a file was uploaded
        if "image" not in request.files:
            return jsonify({"error": "No image file provided. Use 'image' as the form field name."}), 400

        file = request.files["image"]
        if file.filename == "":
            return jsonify({"error": "No file selected"}), 400

        # Step 1: Validate the image
        try:
            image = validate_image(file)
        except ValueError as e:
            return jsonify({"error": f"Image validation failed: {str(e)}"}), 400

        # Step 2: Check pixel range for anomalies
        try:
            check_pixel_range(image)
        except ValueError as e:
            return jsonify({"error": f"Pixel validation failed: {str(e)}"}), 400

        # Step 3: Apply JPEG compression defense (removes high-frequency adversarial perturbations)
        image = apply_jpeg_compression_defense(image)

        # Step 4: Standard preprocessing
        input_tensor = PREPROCESS(image).unsqueeze(0)

        # Step 5: Apply spatial smoothing defense
        input_tensor = apply_spatial_smoothing(input_tensor)

        # Step 6: Run inference
        with torch.no_grad():
            logits = model(input_tensor)
            probabilities = F.softmax(logits, dim=1).squeeze(0)

        # Step 7: Check for adversarial signals
        is_suspicious, adversarial_reasons = detect_adversarial_signals(
            input_tensor, logits, probabilities
        )

        if is_suspicious:
            logger.warning(
                f"Potential adversarial input detected from {request.remote_addr}: {adversarial_reasons}"
            )

        # Step 8: Get top prediction
        top_prob, top_idx = probabilities.max(0)
        confidence = top_prob.item()
        predicted_class_idx = top_idx.item()
        predicted_class = IMAGENET_CLASSES[predicted_class_idx] if predicted_class_idx < len(IMAGENET_CLASSES) else f"class_{predicted_class_idx}"

        # Step 9: Apply confidence threshold
        if confidence < CONFIDENCE_THRESHOLD:
            return jsonify({
                "error": "Prediction confidence too low - image may be out of distribution or adversarial",
                "confidence": round(confidence, 6),
                "flagged_as_suspicious": is_suspicious,
            }), 422

        # Step 10: Get top-5 predictions for additional context
        top5_probs, top5_indices = probabilities.topk(5)
        top5 = []
        for prob, idx in zip(top5_probs, top5_indices):
            cls_name = IMAGENET_CLASSES[idx.item()] if idx.item() < len(IMAGENET_CLASSES) else f"class_{idx.item()}"
            top5.append({
                "class_index": idx.item(),
                "class_name": cls_name,
                "confidence": round(prob.item(), 6),
            })

        response = {
            "predicted_class": predicted_class,
            "class_index": predicted_class_idx,
            "confidence": round(confidence, 6),
            "top5_predictions": top5,
            "flagged_as_suspicious": is_suspicious,
        }

        if is_suspicious:
            response["adversarial_warning"] = (
                "This input was flagged as potentially adversarial. "
                "Results may be unreliable."
            )
            response["adversarial_reasons"] = adversarial_reasons

        return jsonify(response), 200

    except Exception as e:
        logger.error(f"Unexpected error during prediction: {str(e)}", exc_info=True)
        return jsonify({"error": "Internal server error during prediction"}), 500


